/* For this widget */
.task-info-tooltip-style {
  opacity: 1; /* Override Bootstrap's value so any HTML behind doesn't bleed through */
}

/* 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Tasker Modern Portal - Task Name Hover needs a short delay before showing the popup */
/* styles  ng-template=task-info-tooltip-template */
.task-info-tooltip-content {
  /* max-height: 350px; */ /* Don't set it here since we only want to scroll the Objective data */
  max-width: 530px;
  /* overflow: auto; */ /* Don't scroll the whole containier, we only want to scroll the Objective data */
}

/* 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Tasker Modern Portal - Task Name Hover needs a short delay before showing the popup */
/* styles  ng-template=task-info-tooltip-template */
