  padding: 10px; /* go a little smaller than Bootstrap's modal-body */
}

/* 2.6.0 | 2021-04-26 | mmcc | STRY0100152 - Tasker Modern Portal - Task Name Hover needs a short delay before showing the popup */
/* styles  ng-template=task-info-tooltip-template */
